<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Managed Agents POC</title>
  <style>
    /* dark theme: bg #0f1115, surface #1a1d24, accent #4a9eff,
       text #e6e8eb, muted #7a8290, border #2a2f3a */
    /* flex column: header | #messages (scroll) | #composer */
  </style>
</head>
<body>
  <main id="app">
    <header>Managed Agents POC</header>
    <div id="messages" aria-live="polite"></div>
    <form id="composer">
      <input id="prompt" placeholder="Ask about weather or anything else‚Ä¶" autocomplete="off" />
      <button id="send" type="submit">Send</button>
    </form>
  </main>
