- Monospace for the agent-type badge (Task 4): `font-family: ui-monospace, Menlo, monospace`

**JS behavior:**
```js
const chat = document.getElementById("chat");
const form = document.getElementById("composer");
const input = document.getElementById("prompt");

function appendMessage(role, text, agentType) {
  const div = document.createElement("div");
  div.className = `msg ${role}`;
  if (role === "agent" && agentType) {
    const badge = document.createElement("span");
    badge.className = "badge";
    badge.textContent = `${agentType}-agent`;
    div.appendChild(badge);
  }
  const body = document.createElement("div");
  body.className = "body";
  body.textContent = text;
  div.appendChild(body);
  chat.appendChild(div);
  chat.scrollTop = chat.scrollHeight;
  return div;
}

async function send(prompt) {
  if (!prompt.trim()) return;
  appendMessage("user", prompt);
  input.value = "";
  input.disabled = true;
  const loading = appendMessage("agent", "‚Ä¶thinking‚Ä¶");
  loading.classList.add("loading");
  try {
    const r = await fetch("/api/chat", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ prompt })
    });
    const data = await r.json();
    loading.remove();
    if (!r.ok) {
      appendMessage("agent", `Error: ${data.error || r.statusText}`);
    } else {
      appendMessage("agent", data.response, data.agentType);
    }
  } catch (err) {
    loading.remove();
    appendMessage("agent", `Network error: ${err.message}`);
  } finally {
    input.disabled = false;
    input.focus();
  }
}

form.addEventListener("submit", (e) => {
  e.preventDefault();
  send(input.value);
});
```

**Accessibility hygiene:**
- `<label>` for the input (visually hidden if needed)
- `aria-live="polite"` on `#chat` so screen readers announce new messages
- Enter key submits (default form behavior ‚Äî no extra code)

